726: // process compares pods by largest consumer of process number relative to request.
727: func process(stats statsFunc) cmpFunc {
728: 	return func(p1, p2 *v1.Pod) int {
729: 		p1Stats, p1Found := stats(p1)
730: 		p2Stats, p2Found := stats(p2)
731: 		if !p1Found || !p2Found {
732: 			// prioritize evicting the pod for which no stats were found
733: 			return cmpBool(!p1Found, !p2Found)
734: 		}
735: 
736: 		p1Process := processUsage(p1Stats.ProcessStats)
737: 		p2Process := processUsage(p2Stats.ProcessStats)
738: 		return int(p2Process - p1Process)
739: 	}
740: }
