742: // exceedDiskRequests compares whether or not pods' disk usage exceeds their requests
743: func exceedDiskRequests(stats statsFunc, fsStatsToMeasure []fsStatsType, diskResource v1.ResourceName) cmpFunc {
744: 	return func(p1, p2 *v1.Pod) int {
745: 		p1Stats, p1Found := stats(p1)
746: 		p2Stats, p2Found := stats(p2)
747: 		if !p1Found || !p2Found {
748: 			// prioritize evicting the pod for which no stats were found
749: 			return cmpBool(!p1Found, !p2Found)
750: 		}
751: 
752: 		p1Usage, p1Err := podDiskUsage(p1Stats, p1, fsStatsToMeasure)
753: 		p2Usage, p2Err := podDiskUsage(p2Stats, p2, fsStatsToMeasure)
754: 		if p1Err != nil || p2Err != nil {
755: 			// prioritize evicting the pod which had an error getting stats
756: 			return cmpBool(p1Err != nil, p2Err != nil)
757: 		}
758: 
759: 		p1Disk := p1Usage[diskResource]
760: 		p2Disk := p2Usage[diskResource]
761: 		p1ExceedsRequests := p1Disk.Cmp(v1resource.GetResourceRequestQuantity(p1, diskResource)) == 1
762: 		p2ExceedsRequests := p2Disk.Cmp(v1resource.GetResourceRequestQuantity(p2, diskResource)) == 1
763: 		// prioritize evicting the pod which exceeds its requests
764: 		return cmpBool(p1ExceedsRequests, p2ExceedsRequests)
765: 	}
766: }
