768: // disk compares pods by largest consumer of disk relative to request for the specified disk resource.
769: func disk(stats statsFunc, fsStatsToMeasure []fsStatsType, diskResource v1.ResourceName) cmpFunc {
770: 	return func(p1, p2 *v1.Pod) int {
771: 		p1Stats, p1Found := stats(p1)
772: 		p2Stats, p2Found := stats(p2)
773: 		if !p1Found || !p2Found {
774: 			// prioritize evicting the pod for which no stats were found
775: 			return cmpBool(!p1Found, !p2Found)
776: 		}
777: 		p1Usage, p1Err := podDiskUsage(p1Stats, p1, fsStatsToMeasure)
778: 		p2Usage, p2Err := podDiskUsage(p2Stats, p2, fsStatsToMeasure)
779: 		if p1Err != nil || p2Err != nil {
780: 			// prioritize evicting the pod which had an error getting stats
781: 			return cmpBool(p1Err != nil, p2Err != nil)
782: 		}
783: 
784: 		// adjust p1, p2 usage relative to the request (if any)
785: 		p1Disk := p1Usage[diskResource]
786: 		p2Disk := p2Usage[diskResource]
787: 		p1Request := v1resource.GetResourceRequestQuantity(p1, v1.ResourceEphemeralStorage)
788: 		p1Disk.Sub(p1Request)
789: 		p2Request := v1resource.GetResourceRequestQuantity(p2, v1.ResourceEphemeralStorage)
790: 		p2Disk.Sub(p2Request)
791: 		// prioritize evicting the pod which has the larger consumption of disk
792: 		return p2Disk.Cmp(p1Disk)
793: 	}
794: }
